import React from 'react'
import { Navbar, Nav, NavItem, NavDropdown, MenuItem } from 'react-bootstrap';
import { LinkContainer } from "react-router-bootstrap";
import Link from 'gatsby-link'
import Project from '../components/project'
import Career from '../components/career'
import About from '../components/about'
import Contact from '../components/contact'
import Resume from '../components/resume'
import styles from "./header.css"

const MyHeader = () => (
  <Navbar collapseOnSelect fluid>
    <Navbar.Header >
      <Navbar.Brand>
        <a href="/"  className="header">
        Neel Patel
        </a>
      </Navbar.Brand>
      <Navbar.Toggle />
    </Navbar.Header>
    <Navbar.Collapse>
      <Nav pullRight >
        <LinkContainer to="/about" style={{color:"white"}}>
          <NavItem eventKey={1}>
          <div className="mytooltip">
          <span><About /> </span>
          <span className="mytooltiptext">About Me</span>
          </div>
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/projects" style={{color:"white"}}>

          <NavItem eventKey={2}>
          <div className="mytooltip">
          <span><Project /></span>
          <span className="mytooltiptext">Projects</span>
          </div>
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/career" style={{color:"white"}}>
          <NavItem eventKey={3}>
            <div className="mytooltip">
            <span><Career /></span>
            <span className="mytooltiptext">My Career</span>
            </div>
          </NavItem>
        </LinkContainer>
        <LinkContainer to="/resume" style={{color:"white"}}>
          <NavItem eventKey={3}>
            <div className="mytooltip">
            <span><Resume /></span>
            <span className="mytooltiptext">Resume</span>
            </div>
          </NavItem>
        </LinkContainer>
        <NavDropdown eventKey={4} title={<div className="mytooltip"><span><Contact /></span> <span className="mytooltiptext">Contact Me</span></div>} id="basic-nav-dropdown">
          <MenuItem eventKey={4.1} href="https://github.com/neelpatel14">Github</MenuItem>
          <MenuItem eventKey={4.2} href="https://www.linkedin.com/in/npatel14">LinkedIn</MenuItem>
          <MenuItem eventKey={4.3}href="mailto:patel.neel4550@gmail.com?Subject=Work%20Offer">Email</MenuItem>
        </NavDropdown>
      </Nav>
    </Navbar.Collapse>
  </Navbar>
)

export default MyHeader;



